<script>(function(){try{\nif(window.__nyCollapseTimeoutBound) return;\nwindow.__nyCollapseTimeoutBound = true;\ndocument.addEventListener("click", function(e){try{\n  var hdr = e.target && e.target.closest ? e.target.closest(".st-region-header") : null;\n  if(!hdr) return;\n  var mode = (hdr.getAttribute("data-toggle-mode") || "header");\n  if(mode === "title" && !(e && e.target && e.target.closest && e.target.closest(".st-region-title"))) return;\n  if(mode === "icon" && !(e && e.target && e.target.closest && e.target.closest(".st-region-toggle"))) return;\n  var box = hdr.closest ? hdr.closest(".st-region") : null;\n  var body = box ? box.querySelector(".st-region-body") : null;\n  var expDur = 0.8;\n  try{\n    var cs = getComputedStyle(hdr);\n    var d = parseFloat((cs.getPropertyValue("--exp-dur") || "").replace("s",""));\n    if (isFinite(d) && d > 0) expDur = d;\n  }catch(_e){}\n  var cbg = (hdr.getAttribute("data-cbg-mode") || "none");\n  var colr = (hdr.getAttribute("data-cbg-color") || "");\n  var ga = (hdr.getAttribute("data-cbg-a") || "");\n  var gb = (hdr.getAttribute("data-cbg-b") || "");\n  var gang = (hdr.getAttribute("data-cbg-ang") || "");\n  function applyCollapsedBg(){\n    if(cbg==="glass"){ hdr.classList.add("hdr-mode-glass"); hdr.style.background=""; }\n    else if(cbg==="solid"){ hdr.classList.remove("hdr-mode-glass"); hdr.style.background=colr||""; }\n    else if(cbg==="gradient"){ hdr.classList.remove("hdr-mode-glass"); var angNum=parseFloat(gang); if(!isFinite(angNum))angNum=135; hdr.style.background="linear-gradient("+angNum+"deg, "+(ga||"#6a717c")+", "+(gb||"#97aec8")+")"; }\n    else{ hdr.classList.remove("hdr-mode-glass"); hdr.style.background=""; }\n  }\n  function clearCollapsedBg(){ hdr.classList.remove("hdr-mode-glass"); hdr.style.background=""; }\n  var timeout = Math.max(0, Math.min(3000, Math.round(expDur * 1000 + 120)));\n  var fired = false;\n  var mark = function(){ fired = true; };\n  hdr.addEventListener("animationend", mark, { once: true });\n  setTimeout(function(){ try{\n    if(fired) return;\n    if(!box) return;\n    var isCol = box.classList.contains("collapsed");\n    if(isCol){ box.classList.add("collapsed"); if(body) body.style.display = "none"; applyCollapsedBg(); }\n    else { box.classList.remove("collapsed"); if(body) body.style.display = ""; clearCollapsedBg(); }\n  }catch(_ee){} }, timeout);\n}catch(_err){}}, true);\n}catch(_err2){}})();</script>

